command:
$ErrorActionPreference = 'Stop'
$branch = 'codex/issue-306-function-reachability-report'
$runnerPath = 'scripts/openrouter_pr_review_hardened.py'
$selftestPath = 'scripts/openrouter_pr_review_hardened_selftest.py'

function Invoke-Git([string[]]$GitArgs) {
  Write-Host "git $($GitArgs -join ' ')"
  $output = & git @GitArgs
  $code = $LASTEXITCODE
  if ($output) { $output | Out-Host }
  if ($code -ne 0) { throw "git failed with exit $code`: git $($GitArgs -join ' ')" }
}

try {
  Invoke-Git @('fetch', '--no-tags', 'origin', "refs/heads/$branch`:refs/remotes/origin/$branch")
  Invoke-Git @('checkout', '-B', $branch, "origin/$branch")
  Invoke-Git @('config', 'user.name', 'github-actions[bot]')
  Invoke-Git @('config', 'user.email', '41898282+github-actions[bot]@users.noreply.github.com')

  $fixScript = @'
from pathlib import Path

path = Path("scripts/openrouter_pr_review_hardened.py")
text = path.read_text(encoding="utf-8")
changed = False

bad_newline = '''    return re.sub(r"\s+", " ", "
".join(parts)).strip()'''
good_newline = '''    return re.sub(r"\s+", " ", "\\n".join(parts)).strip()'''
if bad_newline in text:
    text = text.replace(bad_newline, good_newline, 1)
    changed = True
    print("fixed malformed newline join in finding_text_for_quality")

backspace_count = text.count("\x08")
if backspace_count:
    text = text.replace("\x08", "\\b")
    changed = True
    print(f"replaced {backspace_count} accidental control-backspace regex boundary characters")

if not changed:
    start = text.find("NON_ACTIONABLE_FINDING_PATTERNS")
    end = text.find("def sanitize_github_output")
    preview = text[start:end] if start != -1 and end != -1 else "<pattern preview unavailable>"
    helper_start = text.find("def finding_text_for_quality")
    helper_end = text.find("def non_actionable_finding_reason")
    helper = text[helper_start:helper_end] if helper_start != -1 and helper_end != -1 else "<helper preview unavailable>"
    raise SystemExit(f"no syntax or boundary fix applied; patterns={preview!r}; helper={helper!r}")

path.write_text(text, encoding="utf-8")
'@
  $scriptPath = Join-Path $env:RUNNER_TEMP 'fix_dcoir_review_nonactionable_syntax_boundary.py'
  $fixScript | Set-Content -LiteralPath $scriptPath -Encoding UTF8
  python $scriptPath
  if ($LASTEXITCODE -ne 0) { throw 'syntax/boundary fix script failed' }

  python -m py_compile $runnerPath $selftestPath
  if ($LASTEXITCODE -ne 0) { throw 'py_compile failed after syntax/boundary fix' }
  python $selftestPath
  if ($LASTEXITCODE -ne 0) { throw 'hardened selftest failed after syntax/boundary fix' }
  Invoke-Git @('diff', '--check', '--', $runnerPath, $selftestPath)

  & git diff --quiet -- $runnerPath
  $diffCode = $LASTEXITCODE
  if ($diffCode -eq 0) { throw 'syntax/boundary fix produced no runner diff' }
  if ($diffCode -ne 1) { throw "git diff failed for $runnerPath with exit $diffCode" }
  Invoke-Git @('add', '--', $runnerPath)
  Invoke-Git @('commit', '-m', 'Fix dcoir review non-actionable syntax and boundaries')
  Invoke-Git @('push', 'origin', "HEAD:refs/heads/$branch")
  Write-Host 'Pushed branch head:'
  Invoke-Git @('rev-parse', 'HEAD')
}
finally {
  try {
    & git diff --quiet -- $runnerPath
    if ($LASTEXITCODE -eq 1) { Invoke-Git @('checkout', '--', $runnerPath) }
    Invoke-Git @('fetch', '--no-tags', 'origin', 'main')
    Invoke-Git @('checkout', '-B', 'main', 'origin/main')
    Invoke-Git @('status', '--short')
  } catch {
    Write-Warning "Unable to restore workflow workspace to main: $_"
  }
}
